def normalize_dates(value: str) -> str:
    """Attempt to normalize date-like strings to ISO format (YYYY-MM-DD)."""
    if not isinstance(value, str) or not value:
        return value
    for fmt in ("%m/%d/%Y", "%d-%m-%Y", "%m-%d-%Y", "%Y/%m/%d", "%d.%m.%Y"):
        try:
            dt = datetime.strptime(value, fmt)
            return dt.strftime("%Y-%m-%d")
        except ValueError:
            continue
    return value


def clean_phone(value: str) -> str:
    """Normalize phone numbers to a consistent format: (XXX) XXX-XXXX."""
    if not isinstance(value, str) or not value:
        return value
    digits = re.sub(r'\D', '', value)
    if len(digits) == 11 and digits.startswith('1'):
        digits = digits[1:]
    if len(digits) == 10:
        return f"({digits[:3]}) {digits[3:6]}-{digits[6:]}"
    return value  # return as-is if not a standard 10-digit number


